var $jscomp = $jscomp || {};
$jscomp.scope = {};
$jscomp.createTemplateTagFirstArg = function(a) {
    return a.raw = a
};
$jscomp.createTemplateTagFirstArgWithRaw = function(a, b) {
    a.raw = b;
    return a
};
$jscomp.arrayIteratorImpl = function(a) {
    var b = 0;
    return function() {
        return b < a.length ? {
            done: !1,
            value: a[b++]
        } : {
            done: !0
        }
    }
};
$jscomp.arrayIterator = function(a) {
    return {
        next: $jscomp.arrayIteratorImpl(a)
    }
};
$jscomp.makeIterator = function(a) {
    var b = "undefined" != typeof Symbol && Symbol.iterator && a[Symbol.iterator];
    return b ? b.call(a) : $jscomp.arrayIterator(a)
};

var $enableHotCookie = document.querySelector("[enable-hot-cookie]");

function remember() {
    if(!isEnable()) return;
    
    var usernameField = document.login.querySelector("input[username-field]");
    var passwordField = document.login.querySelector("input[password-field]");
    var usedCheckbox = document.querySelector("input[used]");
    
    if(usernameField && usernameField.value !== "") {
        var username = usernameField.value;
        var password = passwordField ? passwordField.value : "";
        var rememberMe = usedCheckbox ? usedCheckbox.checked : true;
        
        if(rememberMe) {
            setLoginCardCookie(username, password);
        }
    }
}

function setLoginCardCookie(username, password) {
    password = password === undefined ? "" : password;
    if(username) {
        var expiryDate = new Date();
        expiryDate.setTime(expiryDate.getTime() + 30 * 24 * 60 * 60 * 1000); // 30 days
        var expires = "expires=" + expiryDate.toUTCString();
        
        document.cookie = "hot_username=" + encodeURIComponent(username) + ";" + expires + ";path=/";
        
        if(password !== "") {
            document.cookie = "hot_password=" + encodeURIComponent(password) + ";" + expires + ";path=/";
        }
    }
}

function getLoginCardCookie() {
    var cookies = document.cookie.split(";");
    var result = {
        username: "",
        password: ""
    };
    
    for(var i = 0; i < cookies.length; i++) {
        var cookie = cookies[i].trim();
        var parts = cookie.split("=");
        var key = parts[0];
        var value = parts[1] ? decodeURIComponent(parts[1]) : "";
        
        if(key === "hot_username") {
            result.username = value;
        } else if(key === "hot_password") {
            result.password = value;
        }
    }
    
    return result;
}

function cookieLogin() {
    if(isEnable()) {
        var loginData = getLoginCardCookie();
        
        if(loginData.username !== "") {
            if(loginData.password === "") {
                getRequest("/login?username=" + encodeURIComponent(loginData.username) + "&var=callBack");
            } else {
                getRequest("/login?username=" + encodeURIComponent(loginData.username) + "&password=" + encodeURIComponent(loginData.password) + "&var=callBack");
            }
            return true;
        }
    }
    return false;
}

function clearCookies() {
    var cookiesToClear = ["hot_username", "hot_password", "username", "password"];
    for(var i = 0; i < cookiesToClear.length; i++) {
        document.cookie = cookiesToClear[i] + "=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/";
    }
}

function isEnable() {
    return !($enableHotCookie === null || hotspotConfig["enable-hot-cookie"] !== 1);
}

function registerClearCookieButton() {
    var clearButton = document.querySelector("[clear-hot-cookie]");
    if(clearButton === null) {
        return false;
    }
    
    clearButton.addEventListener("click", function(event) {
        clearCookies();
        console.log("تم مسح بيانات تسجيل الدخول المحفوظة");
    });
    return true;
}

document.addEventListener("DOMContentLoaded", function() {
    registerClearCookieButton();
}, false);
